%[text] # **Reflectron Correction - Grid points extraction of the calibration grid**
%[text] **This workflow colculates the individual grid points of the calibration grid for an atom probe. Prerequisite is dataset acquired with a grid "shadow mask" behind the electrode. After the grid points are extracted, the user can correct every dataset acquired with the atom probe.**
%[text] This workflow requires the installation of the open source software for visualisation aspects Blender 2.91.0 https://www.blender.org/
%[text] Prerequisite: Image Processing Toolbox in Matlab
%%
%[text] ## Constants definition
%[text] defines the constants
calibrationPara.GRIDPITCH = 0.2781228; %[mm] 
calibrationPara.FDMRESOLUTION = 512; % resolution of the FDM
  %[control:button:2645]{"position":[1,2]}
%%
%[text] ## Data loading
%[text] Starting point is an \*.epos file from a reflectron atom probe
[file, path] = uigetfile({'*.epos'},'Select an epos file');
fileName = [path file];
calibrationPara.path = path;
calibrationPara.file = file;
pos = posToTable(fileName);
  %[control:button:440b]{"position":[1,2]}
%%
%[text] ## Calculation of field desorption map
f = figure; %[output:6dc6f0c8]
ax = axes; %[output:6dc6f0c8]
calibrationPara.FDMRESOLUTION = 512; % number of pixels for the field desorption map
[FDM, FDMcenters] = hist3(double([pos.detx pos.dety]),'Nbins',[calibrationPara.FDMRESOLUTION calibrationPara.FDMRESOLUTION]); %[output:87f8b579]
FDMimage = imagesc(FDM,'XData',FDMcenters{1},'YData',FDMcenters{2});
axis equal;
axis tight;
xlabel 'detector x [mm]'
ylabel 'detector y [mm]'
ax = gca;
ax.YDir = 'normal';
ax.XDir = 'normal';
hold on
%[text] ## Edge extraction
%[text] find the optimum threshold value by changing it and visual observation. Important: the grid bar width should be seen in between the red lines and reduce the artefacts inside the squares
% find threshold value
calibrationPara.THRESHOLDFAC = 0.03; % to biarize the image for canny edge detection %[control:slider:4899]{"position":[32,36]}
threshold = max(FDM(:)) * calibrationPara.THRESHOLDFAC;
edgeBinary = edge(FDM > threshold,"canny");
[edgeY, edgeX] = find(edgeBinary);
edgeX = FDMcenters{1}(edgeX); edgeX = edgeX';% conversion from pixels to coordinates
edgeY = FDMcenters{2}(edgeY); edgeY = edgeY';% conversion from pixels to coordinates
s = scatter(edgeX,edgeY,'.r');
  %[control:button:77f1]{"position":[1,2]}
%%
%[text] ## Generation of patch object and export to .obj
%[text] Save the obj in a folder and continue with Blender
fv.vertices = [edgeX,edgeY,zeros(size(edgeX))];
fv.faces = [];
% save object
objName = '4000XR_Erlangen_4604_gridPointsMesh'; %[control:editfield:4fbc]{"position":[11,48]}
objFileName = [objName '_reflectronCalibrationGridEdgesRaw.obj']; 
patchToObj(fv,objName,objFileName);

% if you want to save the calibration Parameter
save('calibrationPara');

clearvars -except pos calibrationPara

  %[control:button:9ebc]{"position":[1,2]}
%%
%[text] ## Clean up and identify individual grid lines in Blender
%[text] - Import .obj in Blender \
%[text] ![](text:image:18f1) ![](text:image:8d92)
%[text] - Edit Mode 
%[text] - 'C' -\> circle selection - select lines - 'Esc' - 'P' \> 'Selection' - new object 
%[text] - name objects along direction & index
%[text] - export as .obj \
%[text] naming convention for edge objects in Blender: \[linedirection lineIndex edgedirection\] e.g.: X-1P, Y+0P
%[text] lineDirection... X or Y
%[text] lineIndex relative to to grid origin
%[text] ![](text:image:6209)
%[text] *Export it back as .obj for Matlab*
%[text] ![](text:image:263e)
%%
%[text] ## Reimport of cleaned mesh 
%[text] import lines again from Blender
[objFile, objPath] = uigetfile({'*.obj'},'select obj file');
fileID = fopen([objPath objFile],'r');
formatSpec = '%c';
objText = string(fscanf(fileID,formatSpec));
objText = splitlines(objText);
objText(objText == "") = []; % remove empty lines
objStartIdx = find(startsWith(objText,"o"));
objEndIdx = [objStartIdx(2:end)-1; length(objText)];
objNames = extractBetween(objText(objStartIdx),3, 6);
xIdxRange = [0 0]; % ranges of indices that are encountered
yIdxRange = [0 0];

% preallocation
objects = cell(length(objNames),1);
 
% extract single point line from object
for o = 1:length(objNames)
    verticesTMP = extractAfter(objText(objStartIdx(o)+1:objEndIdx(o)),2);
    vertices = zeros(length(verticesTMP),3);
    for v = 1:length(verticesTMP)
        vertices(v,:) = str2num(verticesTMP(v));
    end
    objects{o,1}.vertices = vertices;
    vertices = [];
    objects{o,1}.name = objNames(o);
    objects{o,1}.lineDirection = extractBetween(objNames(o),1, 1);
    objects{o,1}.lineIdx = str2num(extractBetween(objNames(o),2, 3));
    objects{o,1}.lineEdgeSide = extractBetween(objNames(o),4, 4);
    
    % calculate range of indices
    if strcmp(objects{o}.lineDirection, 'X')
        if objects{o}.lineIdx < xIdxRange(1)
            xIdxRange(1) = objects{o}.lineIdx;
        elseif objects{o}.lineIdx > xIdxRange(2)
            xIdxRange(2) = objects{o}.lineIdx;
        end
    else
        if objects{o}.lineIdx < yIdxRange(1)
            yIdxRange(1) = objects{o}.lineIdx;
        elseif objects{o}.lineIdx > yIdxRange(2)
            yIdxRange(2) = objects{o}.lineIdx;
        end
    end
end
%clearvars -except objects pos calibrationPara
  %[control:button:43d5]{"position":[1,2]}
%%
%[text] ## Creating of fitAdvice
%[text] Take the marked object lines and fit a line to it with the fit function and the parameter Splinefittingparameter.
% plotting of objects
calibrationPara.SPLINEFITTINGPARAMETER = 0.06;
f = figure(); %[output:8196ea25]
ax = axes(); %[output:8196ea25]
axis equal; %[output:8196ea25]
hold on %[output:8196ea25]
for o=1:length(objects)
    s(o) = scatter(objects{o}.vertices(:,1),objects{o}.vertices(:,2),'.'); %[output:8196ea25]
    s(o).DisplayName = objects{o}.name;
    [xData, yData] = prepareCurveData(objects{o}.vertices(:,1),objects{o}.vertices(:,2));
    ft = fittype( 'smoothingspline' );
    opts = fitoptions( 'Method', 'SmoothingSpline' );
    opts.SmoothingParam = calibrationPara.SPLINEFITTINGPARAMETER;
    [objects{o}.fit, objects{o}.gof] = fit( xData, yData, ft ,opts);
    p(o) = plot(objects{o}.fit);
    %pause(1);
    %delete(s(o));
    delete(p(o));
end
ax.XLim = [-20 20]; %[output:8196ea25]
ax.YLim = [-20 20]; %[output:8196ea25]
legend off %[output:8196ea25]

% split in lines for x and y directions
xLines = objects(cellfun(@(x) strcmp(x.lineDirection, 'X'),objects));
yLines = objects(cellfun(@(x) strcmp(x.lineDirection, 'Y'),objects));
% clearvars -except objects pos calibrationPara FDMRESOLUTION GRIDBARWIDTH GRIDPITCH THRESHOLDFAC SPLINEFITTINGPARAMETER xData xLines yData yLines
  %[control:button:8c58]{"position":[1,2]}
%%
%[text] ## Finding intersection points between lines
% plots FDM again
figure; %[output:42b0a0ec]
axes; %[output:42b0a0ec]
[FDM, FDMcenters] = hist3(double([pos.detx pos.dety]),'Nbins',[calibrationPara.FDMRESOLUTION calibrationPara.FDMRESOLUTION]);
FDMimage = imagesc(FDM,'XData',FDMcenters{1},'YData',FDMcenters{2}); %[output:42b0a0ec]
axis equal; %[output:42b0a0ec]
axis tight; %[output:42b0a0ec]
xlabel 'detector x [mm]' %[output:42b0a0ec]
ylabel 'detector y [mm]' %[output:42b0a0ec]
ax = gca;
ax.YDir = 'normal'; %[output:42b0a0ec]
ax.XDir = 'normal'; %[output:42b0a0ec]
hold on;  %[output:42b0a0ec]
% range for intersection search and number of bins. 
% Keep limits as close as possible to avoid intersections of spline fits far away from actual intersection point.
locs = linspace(-25,25,1e5); 

% preallocation
intersectionName = strings(length(xLines), length(yLines));
intersectionX = zeros(length(xLines), length(yLines));
intersectionY = zeros(length(xLines), length(yLines));

for xIdx = 1:length(xLines)
    for yIdx = 1:length(yLines)
        txt = xLines{xIdx}.name + yLines{yIdx}.name;
        intersectionName(xIdx,yIdx) = txt; 
        func = xLines{xIdx}.fit(locs) - yLines{yIdx}.fit(locs);
        intersectionX(xIdx,yIdx) = locs(abs(func) == min(abs(func)));
        intersectionY(xIdx,yIdx) = xLines{xIdx}.fit(intersectionX(xIdx,yIdx));
%         Plots the points with name
%         scatter(intersectionX(xIdx,yIdx),intersectionY(xIdx,yIdx));
%         text(intersectionX(xIdx,yIdx),intersectionY(xIdx,yIdx),txt);
    end
end

% plot single cross for each intersection
% figure;
% scatter(intersectionX(1:xIdx,1:yIdx),intersectionY(1:xIdx,1:yIdx));

% combine intersection corners to points and calculate distortion
gridIntersectionCornerName = erase(intersectionName,["M", "P"]);
gridIntersectionNamesList = unique(gridIntersectionCornerName);

% preallocation
detectorIntersectionX = zeros(length(gridIntersectionNamesList),1);
detectorIntersectionY = zeros(length(gridIntersectionNamesList),1);
numberOfCorners = zeros(length(gridIntersectionNamesList),1);
gridXIdx = zeros(length(gridIntersectionNamesList),1);
gridYIdx = zeros(length(gridIntersectionNamesList),1);
gridIntersectionX = zeros(length(gridIntersectionNamesList),1);
gridIntersectionY = zeros(length(gridIntersectionNamesList),1);

for i = 1:length(gridIntersectionNamesList)
    % calculate intersection coordinates on detector
    detectorIntersectionX(i,1) = mean(intersectionX(gridIntersectionCornerName == gridIntersectionNamesList(i)));
    detectorIntersectionY(i,1) = mean(intersectionY(gridIntersectionCornerName == gridIntersectionNamesList(i)));
    % scatter(detectorIntersectionX(i),detectorIntersectionY(i),'x');
    % text(detectorIntersectionX(i),detectorIntersectionY(i),gridIntersectionNamesList(i));
    numberOfCorners(i,1) = nnz(gridIntersectionCornerName == gridIntersectionNamesList(i));
    gridXIdx(i,1) = str2num(extractBetween(gridIntersectionNamesList(i),2,3));
    gridYIdx(i,1) = str2num(extractBetween(gridIntersectionNamesList(i),5,6));
    
    % claculate intersection coordinates on grid
    gridIntersectionX(i,1) = gridXIdx(i) * calibrationPara.GRIDPITCH;
    gridIntersectionY(i,1) = gridYIdx(i) * calibrationPara.GRIDPITCH;
    
end

% final positions of the intersections
intersections = table(gridIntersectionNamesList,gridXIdx, gridYIdx,...
    detectorIntersectionX,detectorIntersectionY,...
    numberOfCorners,...
    gridIntersectionX, gridIntersectionY,...
    'VariableNames',["intersection","xIdx","yIdx","detectorX","detectorY","corners","gridX","gridY"]);

scatter(intersections.detectorX,intersections.detectorY, 'x', 'MarkerEdgeColor', [0.8500 0.3250 0.0980]); %[output:42b0a0ec]
hold on %[output:42b0a0ec]

intersections = sortrows(intersections,{'xIdx','yIdx'});
% clearvars -except objects pos calibrationPara intersections 
  %[control:button:243b]{"position":[1,2]}
%%
%[text] ## Add the extrapolation for each row through the intersections in x direction and add the triangulation
% Parameters for Extrapolation
calibrationPara.extrapMode = 'linear';
calibrationPara.alpha = 10; % [mm] alpha value for triangulation
xIndices = sort(unique(intersections.xIdx));
yIndices = sort(unique(intersections.yIdx));

% x line extrapolation
for ix = 1:length(xIndices)
    xData = intersections.detectorX(intersections.xIdx == xIndices(ix));
    yData = intersections.detectorY(intersections.xIdx == xIndices(ix));
    xTmp = interp1(1:length(xData),xData,0:length(xData)+1,calibrationPara.extrapMode,'extrap');
    yTmp = interp1(1:length(yData),yData,0:length(yData)+1,calibrationPara.extrapMode,'extrap');
    detectorX = [xTmp(1); xTmp(end)];
    detectorY = [yTmp(1); yTmp(end)];
    xIdx = [xIndices(ix); xIndices(ix)];
    yIdx = [min(yIndices)-1; max(yIndices)+1];
    corners = [0;0];
    gridX = xIdx * calibrationPara.GRIDPITCH;
    gridY = yIdx * calibrationPara.GRIDPITCH;
    
    % Write correct name
    if yIdx(1)>=0
        y1Name = ['Y' '+' num2str(yIdx(1))];
    else
        y1Name = ['Y' num2str(yIdx(1))];
    end
    if yIdx(2)>=0
        y2Name = ['Y' '+' num2str(yIdx(2))];
    else
        y2Name = ['Y' num2str(yIdx(2))];
    end
    if xIndices(ix)>=0
        xName = ['X' '+' num2str(xIndices(ix))];
    else
        xName = ['X' num2str(xIndices(ix))];
    end
    names =[string([xName y1Name]);...
        string([xName y2Name])];
    
    % create table with properties of extrapolated points
    tblTmp = table(names,xIdx, yIdx,...
    detectorX,detectorY,...
    corners,...
    gridX, gridY,...
    'VariableNames',["intersection","xIdx","yIdx","detectorX","detectorY","corners","gridX","gridY"]);
    intersections = [intersections; tblTmp];
end

gridTris = alphaTriangulation(alphaShape(intersections.detectorX,intersections.detectorY,calibrationPara.alpha));
triplot(gridTris,intersections.detectorX,intersections.detectorY,'g','LineWidth',.5); %[output:19de9b42]
hold on %[output:19de9b42]

% clearvars -except objects pos calibrationPara intersections yIndices xIndices xData xLines yData yLines

  %[control:button:5e0e]{"position":[1,2]}
%%
%[text] ## Add the extrapolation in y direction to include the entire FDM
% y line extrapolation
for iy = 1:length(yIndices)
    xData = intersections.detectorX(intersections.yIdx == yIndices(iy));
    yData = intersections.detectorY(intersections.yIdx == yIndices(iy));
    xTmp = interp1(1:length(xData),xData,0:length(xData)+1,calibrationPara.extrapMode,'extrap');
    yTmp = interp1(1:length(yData),yData,0:length(yData)+1,calibrationPara.extrapMode,'extrap');
    detectorX = [xTmp(1); xTmp(end)];
    detectorY = [yTmp(1); yTmp(end)];
    
    yIdx = [yIndices(iy); yIndices(iy)];
    xIdx = [min(xIndices)-1; max(xIndices)+1];
    corners = [0;0];
    gridX = xIdx * calibrationPara.GRIDPITCH;
    gridY = yIdx * calibrationPara.GRIDPITCH;
    
    
    if xIdx(1)>=0
        x1Name = ['X' '+' num2str(xIdx(1))];
    else
        x1Name = ['X' num2str(xIdx(1))];
    end
    if xIdx(2)>=0
        x2Name = ['X' '+' num2str(xIdx(2))];
    else
        x2Name = ['X' num2str(xIdx(2))];
    end
    if yIndices(iy)>=0
        yName = ['Y' '+' num2str(yIndices(iy))];
    else
        yName = ['Y' num2str(yIndices(iy))];
    end
    names =[string([x1Name yName]);...
        string([x2Name yName])];
    
    tblTmp = table(names,xIdx, yIdx, detectorX, detectorY, corners, gridX, gridY,...
    'VariableNames',["intersection","xIdx","yIdx","detectorX","detectorY","corners","gridX","gridY"]);
    intersections = [intersections; tblTmp];
end 

[gridTris, gridTrisVertices] = alphaTriangulation(alphaShape(intersections.detectorX,intersections.detectorY,calibrationPara.alpha));
triplot(gridTris,gridTrisVertices(:,1), gridTrisVertices(:,2),'g','LineWidth',.5); %[output:1755daa6]
%triplot(gridTris,intersections.detectorX,intersections.detectorY,'g','LineWidth',.5);

%clearvars -except objects pos calibrationPara intersections gridTris gridTrisVertices xData xLines yData yLines
  %[control:button:3cb2]{"position":[1,2]}
%[text] ## **Save intersections - this is your transformation mesh!**
%%
%[text] ## Translating a dataset into virtual detector coordinates
%[text] The user can now use this workflow to correct the data or use the Workflow\_ReflectronCorrection\_Dataset or the function posReflectronCorrected
%[text] loading the dataset to be translated
[transPosName, transPosPath] = uigetfile({'*.epos'},'Select an epos file');
transPosName
transPosPath
fileName = [transPosPath transPosName];
transPos = posToTable(fileName);
  %[control:button:1a63]{"position":[1,2]}
%%
%[text] ## plot FDM
figure;
axes;
FDMRESOLUTION = 512;
[FDM, FDMcenters] = hist3(double([transPos.detx transPos.dety]),'Nbins',[FDMRESOLUTION FDMRESOLUTION]);
imagesc(FDM,'XData',FDMcenters{1},'YData',FDMcenters{2});
axis equal;
axis tight;
xlabel 'detector x [mm]'
ylabel 'detector y [mm]'
ax = gca;
ax.YDir = 'normal';
ax.XDir = 'normal';
hold on;
triplot(gridTris,intersections.detectorX,intersections.detectorY,':g','LineWidth',2);
%triplot(gridTris,gridTrisVertices(:,1), gridTrisVertices(:,2),'g','LineWidth',.5);
  %[control:button:5214]{"position":[1,2]}
%%
%[text] ## Create translation mesh allocation of detector hit points
%[text] reminder: X lines are the one closer to parallel to the x axis. Their position represents y coordinates!
%[text] find triangle for all hit positions inside triangulation on the detector
triangleNumber = tsearchn([intersections.detectorY, intersections.detectorX],gridTris,...
    [transPos.detx, transPos.dety]);
%[text] for stray hit coordinates outside detector: find closest triangle of triangulation
isOutside = find(isnan(triangleNumber));
closestVertex = dsearchn([intersections.detectorY, intersections.detectorX],gridTris,...
    [transPos.detx, transPos.dety]);
for idx = 1:length(isOutside) % MATLAB is finally JIT compiled! :D 
    tetIdx = find(sum(gridTris == closestVertex( isOutside(idx) ) ,2)); 
    triangleNumber(isOutside(idx)) = tetIdx(1);
end
  %[control:button:43ed]{"position":[1,2]}
%%
%[text] ## Performing affine transformation through barycentric coordinate approximation
% defining triangulation objects
detectorTriangulation = triangulation(gridTris,[intersections.detectorY, intersections.detectorX]);
gridTriangulation = triangulation(gridTris,[intersections.gridX, intersections.gridY]);

% carrying out transformations
barycentricCoordinatesPos = cartesianToBarycentric(detectorTriangulation,triangleNumber,[transPos.detx, transPos.dety]);
coords = barycentricToCartesian(gridTriangulation,triangleNumber,barycentricCoordinatesPos);

% creating corrected pos table
posCorrected = transPos;
posCorrected.detx = uminus(coords(:,2));
posCorrected.dety = uminus(coords(:,1));
  %[control:button:35ff]{"position":[1,2]}
%%
%[text] ## Displaying of corrected field desorption map
f = figure;
ax = axes;
[FDM, FDMcenters] = hist3(double([posCorrected.detx  posCorrected.dety]),'Nbins',[FDMRESOLUTION FDMRESOLUTION]);
FDMimage = imagesc(FDM,'XData',FDMcenters{1},'YData',FDMcenters{2});

axis equal;
axis tight;
xlabel 'detector x [mm]'
ylabel 'detector y [mm]'
ax = gca;
ax.YDir = 'normal';
ax.XDir = 'normal';
hold on
title 'corrected field desorption map'

triplot(gridTris,intersections.gridX,intersections.gridY,'g','LineWidth',0.5);

%clearvars -except transPos posCorrected intersections gridTris f ax FDMRESOLUTION
  %[control:button:5578]{"position":[1,2]}

